('REPORT_LIST_OPTIMIZED',  '报表优化分页查询',      '示例系统', 3, '使用子查询优化的深分页报表查询',                      1, 'system', 'system'),
('WEATHER_QUERY',          '天气查询',             '示例系统', 3, '调用外部天气API查询城市天气信息',                      1, 'system', 'system'),
